-- Quick task 260620-gk9 — Backfill 18 missing watches_catalog.image_url values
--   + delete rogue brand='test' model='test' row
--
-- PROD-ONLY — do NOT apply locally.
-- Local watches_catalog has known id divergence (project_catalog-id-divergence) and
-- the natural-key UNIQUE constraint is frequently dropped by drizzle-kit pushes
-- (project_local_catalog_natural_key_drift). Apply to prod only.
--
-- Source: scripts/seed-data/catalog-missing-images.md
-- Generated by: npm run catalog:missing-images (prod, 2026-06-20)
-- 19 of 194 rows were missing image_url (9.8%); 18 are backfilled here; 1 test row deleted.
--
-- Apply via: supabase db push --linked
-- Do NOT use: drizzle-kit push / supabase db reset / local psql
-- Per memory: project_drizzle_supabase_db_mismatch
--
-- Idempotency strategy: every UPDATE includes the guard
--   AND (image_url IS NULL OR btrim(image_url) = '')
-- so re-applying this file to prod is a no-op — it will NOT overwrite any URL
-- the operator has changed by hand since the initial apply.
--
-- watches_catalog is non-wipeable per memory project_db_wipeable_2026_05_09 (LLM/factual/
-- photo enrichment investment). This migration uses UPDATE+DELETE only — no schema change.
--
-- All 18 rows are keyed by (brand, model, reference) natural triple — NEVER by id
-- (per project_catalog-id-divergence: local and prod ids diverge).

BEGIN;

-- Pre-flight: assert all 18 target (brand, model, reference) triples exist in prod catalog.
-- If any triple is missing (e.g. hidden trailing space or smart-quote in source markdown),
-- the transaction rolls back before touching any data.
DO $$
DECLARE found int;
BEGIN
  SELECT count(*) INTO found FROM public.watches_catalog
   WHERE (brand, model, reference) IN (
     ('A. Lange & Söhne', '1815', '233.026'),
     ('A. Lange & Söhne', 'Odysseus', '363.179'),
     ('A. Lange & Söhne', 'Saxonia Thin', '211.027'),
     ('Baume & Mercier', 'Riviera', '10728'),
     ('Blancpain', 'Fifty Fathoms', '5015-1130-71S'),
     ('Certina', 'DS Action GMT Powermatic 80', 'C032.929.11.051.00'),
     ('Christopher Ward', 'The Twelve 40mm', 'C12-40A-S00K0-S00B0-K'),
     ('Jaeger-LeCoultre', 'Master Ultra Thin', 'Q1342520'),
     ('Jaeger-LeCoultre', 'Master Ultra Thin Small Seconds', 'Q1218420'),
     ('Jaeger-LeCoultre', 'Polaris Date', 'Q9068681'),
     ('Omega', 'Seamaster 300', '234.30.41.21.03.001'),
     ('Orient', 'Bambino Version 7', 'FAC0000DD0'),
     ('Rolex', 'Datejust 41', '126334'),
     ('Rolex', 'Explorer 40', '224270'),
     ('Sinn', '856 UTC', '856.010'),
     ('Tudor', 'Black Bay 58 GMT', '7939G1A0NRU'),
     ('Vacheron Constantin', 'Overseas', '4500V/110A-B128'),
     ('Zenith', 'Defy Skyline', '03.9300.3620/01.I001')
   );
  IF found <> 18 THEN
    RAISE EXCEPTION 'pre-flight: expected 18 matching catalog rows, found %', found;
  END IF;
END $$;

