UPDATE public.watches_catalog
   SET image_url = 'https://img.alange-soehne.com/product-slideshow-product-md-2/o-dpr-2/dd4f450ea345e51965dc27a803e2ce3bfbf2c3ef.jpg',
       updated_at = now()
 WHERE brand = 'A. Lange & Söhne'
   AND model = '1815'
   AND reference = '233.026'
   AND (image_url IS NULL OR btrim(image_url) = '');

