-- Defense-in-depth DELETE of the rogue brand='test' model='test' row.
-- Guards: owners_count=0, wishlist_count=0, no watches rows pointing at this catalog entry.
-- This row has 0 owners, 0 wishlist, and was never used — safe to delete.
DELETE FROM public.watches_catalog
 WHERE brand = 'test'
   AND model = 'test'
   AND reference IS NULL
   AND coalesce(owners_count, 0) = 0
   AND coalesce(wishlist_count, 0) = 0
   AND NOT EXISTS (
     SELECT 1 FROM public.watches w WHERE w.catalog_id = watches_catalog.id
   );

-- Post-flight: confirm no targeted row is still missing an image_url,
-- and confirm the test/test row is gone.
DO $$
DECLARE still_missing int;
DECLARE test_row int;
BEGIN
  SELECT count(*) INTO still_missing FROM public.watches_catalog
   WHERE (brand, model, reference) IN (
     ('A. Lange & Söhne', '1815', '233.026'),
     ('A. Lange & Söhne', 'Odysseus', '363.179'),
     ('A. Lange & Söhne', 'Saxonia Thin', '211.027'),
     ('Baume & Mercier', 'Riviera', '10728'),
     ('Blancpain', 'Fifty Fathoms', '5015-1130-71S'),
     ('Certina', 'DS Action GMT Powermatic 80', 'C032.929.11.051.00'),
     ('Christopher Ward', 'The Twelve 40mm', 'C12-40A-S00K0-S00B0-K'),
     ('Jaeger-LeCoultre', 'Master Ultra Thin', 'Q1342520'),
     ('Jaeger-LeCoultre', 'Master Ultra Thin Small Seconds', 'Q1218420'),
     ('Jaeger-LeCoultre', 'Polaris Date', 'Q9068681'),
     ('Omega', 'Seamaster 300', '234.30.41.21.03.001'),
     ('Orient', 'Bambino Version 7', 'FAC0000DD0'),
     ('Rolex', 'Datejust 41', '126334'),
     ('Rolex', 'Explorer 40', '224270'),
     ('Sinn', '856 UTC', '856.010'),
     ('Tudor', 'Black Bay 58 GMT', '7939G1A0NRU'),
     ('Vacheron Constantin', 'Overseas', '4500V/110A-B128'),
     ('Zenith', 'Defy Skyline', '03.9300.3620/01.I001')
   )
     AND (image_url IS NULL OR btrim(image_url) = '');
  IF still_missing > 0 THEN
    RAISE EXCEPTION 'post-flight: % of the 18 targeted rows still missing image_url', still_missing;
  END IF;

  SELECT count(*) INTO test_row FROM public.watches_catalog
   WHERE brand = 'test' AND model = 'test' AND reference IS NULL;
  IF test_row <> 0 THEN
    RAISE EXCEPTION 'post-flight: test/test row was not deleted (count=%)', test_row;
  END IF;
END $$;

COMMIT;
